rule.query:
{
  "selection_cron_dirs": {
    "TargetFilename|startswith": [
      "/etc/cron.d/",
      "/etc/cron.daily/",
      "/etc/cron.hourly/",
      "/etc/cron.monthly/",
      "/etc/cron.weekly/",
      "/var/spool/cron/crontabs/",
      "/var/spool/cron/root"
    ]
  },
  "selection_cron_special_files": {
    "TargetFilename|contains": [
      "/etc/cron.allow",
      "/etc/cron.deny",
      "/etc/crontab"
    ]
  },
  "filter_optional_legit_cron": {
    "TargetFilename": [
      "/etc/cron.daily/apt",
      "/etc/cron.daily/dpkg",
      "/etc/cron.daily/passwd",
      "/etc/crontabs/root"
    ]
  },
  "condition": "1 of selection_* and not 1 of filter_optional_*"
}
